func calLabCellClass(inMonth, isToday, isSelected, highlightWeekend, compact bool) string {
	h := "h-24"
	if compact {
		h = "h-12"
	}
	base := "flex flex-col items-center justify-start p-1 rounded text-base-content cursor-pointer hover:bg-base-300 overflow-hidden " + h
	if !inMonth {
		base += " opacity-30"
	}
	if highlightWeekend {
		base += " bg-base-300/50"
	} else {
		base += " bg-base-100"
	}
	if isSelected {
		base += " ring-2 ring-accent"
	} else if isToday {
		base += " ring-1 ring-primary"
	}
	return base
}

